"use client"

import dynamic from "next/dynamic"

const HydraulicHotspotMapImpl = dynamic(() => import("./hydraulic-hotspot-map-impl"), {
  ssr: false,
  loading: () => <div className="flex h-80 items-center justify-center bg-slate-100 text-sm text-slate-500 dark:bg-slate-900">Loading hydraulic risk map...</div>,
})

export function HydraulicHotspotMap({ geojson }: { geojson: Record<string, unknown> }) {
  return <HydraulicHotspotMapImpl geojson={geojson} />
}
